solutions.command_template:
# In your .tf file, add a moved block:
moved {
  from = module.old.aws_s3_bucket.bucket
  to   = aws_s3_bucket.bucket
}

# In your resource block:
resource "aws_rds_instance" "primary" {
  # ... config ...
  lifecycle {
    prevent_destroy = true
  }
}

# Add to ~/.terraformrc or CI environment:
credentials "registry.terraform.io" {
  token = "<your-token>"
}

# Or set via environment variable:
export TF_TOKEN_registry_terraform_io="<token>"

# In versions.tf or main.tf:
terraform {
  required_version = ">= 1.5.0, < 2.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}
